      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  if (!f.getItemValue('ngay_bc')) f.setItemValue('ngay_bc', new Date());
  changeLookupReadonly(f, 'status', true);
  f.setReferenceKeyFilter('ma_ku');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid;
      var d1 = f.getItem('ngay_vay_from').value;
      var d2 = f.getItem('ngay_vay_to').value;
      var acc = f.getItem('tk').value;
      g._alterTitle = [null, [['%s1', acc ? acc : '*', true], ['%d1', d1, true], ['%d2', d2, true]]];
      g._hiddenFields = [{Fields: 'tien_nt, tien_tt_nt', Value: (f.getItemValue('mau_bc') == '10')}];

      var c = f.getItemValue('so_ngay') + String.fromCharCode(255) + f.getItemValue('mau_bc');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function onChange$LoanContractType(o) {o.parentForm.setReferenceKeyFilter('ma_ku');}
